193→            fun fromIntent(intent: Intent?): Result? {
194→                return if (intent == null) {
195→                    null
196→                } else {
197→                    try {
198→                        val question = intent.getStringExtra(INTENT_QUESTION_FORMAT)
199→                        val answer = intent.getStringExtra(INTENT_ANSWER_FORMAT)
200→                        Result(question, answer)
